var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>스프리건 인자 안정화 완료…/</color>","JPN":"<color=#ffd34c>スプリガン因子の安定化完了……/</color>","ENG":"<color=#ffd34c>Spriggan Factor stabilized.../</color>","TWN":"<color=#ffd34c>守護者因子已穩定……/</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>인자 귀속 및 신체 동기화 개시…/</color>","JPN":"<color=#ffd34c>因子の帰属および身体同期化開始……/</color>","ENG":"<color=#ffd34c>Initiating Factor attribution and body synchronization.../</color>","TWN":"<color=#ffd34c>因子綁定與身體同步開始…… /</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>인격 구성 완료… 사고 프로세스 활성화… 최초 접속 확인…/</color>","JPN":"<color=#ffd34c>人格の構成完了……思考プロセス活性化……初回接続確認……/</color>","ENG":"<color=#ffd34c>Personality construction complete... Thought process activated... First connection confirmed.../</color>","TWN":"<color=#ffd34c>人格構建完成……啟動思維程式……首次連接確認……/</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"안녕, 셰퍼드.","JPN":"おはよう、シェパード。","ENG":"Hello, Shepherd.","TWN":"你好，牧羊犬。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L6_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"반갑구나. 내가 누군지 알아보겠니?","JPN":"初めまして、僕が誰か、わかるかい？","ENG":"A pleasure to meet you. Can you tell who I am?","TWN":"很高興見到你。你認得我是誰嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"...Yes.","TWN":"……嗯。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신은 나의 명령권자… 에드윈 프리하트.","JPN":"あなたはシェパードの命令権者……エッドウィン・プラハト。","ENG":"You are Shepherd's commander... Edwin Freeheart.","TWN":"你是我的指揮官……艾德溫·普立哈特。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Correct.","TWN":"……沒錯。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"새 몸에 적응할 때까지 쉬어두렴. 아픈 곳이 있으면 바로 나한테 말하고.","JPN":"新しい体に慣れるまで休みなさい。痛いところがあったらすぐ僕に話すんだ。","ENG":"Rest until you adjust into your new body. And tell me if it hurts anywhere.","TWN":"在你適應新的身體之前，好好休息吧。如果有哪裡不舒服，馬上告訴我。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"장장 한 달에 걸친 대시술이었어요. 무사히 깨어나서 다행이네요.","JPN":"一か月間の大施術でしたね。無事に目が覚めて安心しました。","ENG":"It was a month-long major surgery. I'm glad it all went well.","TWN":"這是長達一個月的大手術。我很高興她能安全醒來。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"이미 소실된 기억을 복원하는 데엔 실패했지만, 감수할만한 성과예요.","JPN":"すでに消えた記憶の復元には失敗しましたが、それでも素晴らしい成果です。","ENG":"Although we failed to restore the memories that were lost, it still is an achievement.","TWN":"雖然沒能恢復已經失去的記憶，但這是一個值得接受的結果。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"청동나무의 재생작업은 어떻게 되어가죠?","JPN":"青銅の木の再生作業はどうなっていますか？","ENG":"How is the restoration of the Bronze Tree going?","TWN":"青銅樹的再生作業進展如何？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"재생은 실패했습니다. 청동나무는 6일의 탄화 과정을 거쳐 수명을 다했어요.","JPN":"再生は失敗しました。青銅の木は6日間の炭化過程を経て寿命が尽きたんです。","ENG":"Restoration failed. The Bronze Tree died out after 6 days of carbonizing.","TWN":"再生失敗了。青銅樹在經過6天的碳化過程後就達到了其壽命的終點。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"정확히는 우리가 발견한 세계에 존재하는 청동나무가 수명을 다한 거죠.","JPN":"正確には、私たちが発見した世界に存在する全ての青銅の木の寿命が尽きました。","ENG":"To be exact, it's the lifespan of the Bronze Tree that existed in the world that we found reached its end.","TWN":"準確的說，我們世界中發現的青銅樹已經到了它的生命盡頭。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"몰랐어요. 셰퍼드의 심장에 스프리건 인자가 옮겨지자마자 청동나무가 시들어버릴 줄은…","JPN":"知らなかったんです。シェパードの心臓にスプリガン因子が移行してすぐ青銅の木が枯れてしまうなんて……","ENG":"I didn't know that the Bronze Tree would wither away as soon as we transferred the Spriggan Factor into Shepherd's heart...","TWN":"我沒想到，守護者因子一轉移到牧羊犬的心臟，青銅樹就枯萎了……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"청동나무는 발견 당시에도 이미 죽어가고 있었습니다.","JPN":"青銅の木は発見当時からもすでに枯れかけていました。","ENG":"The Bronze Tree was already withering away when we discovered it.","TWN":"這棵青銅樹被發現時，它就已經快死了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"하지만 우리가 셰퍼드를 통해 다시 한번 싹을 틔운 셈이니, 아쉬워할 필요는 없어요.","JPN":"しかし、私たちがシェパードを通じてもう一度芽生えさせたので、残念に思うことはありません。","ENG":"But through Shepherd, it has sprouted new seeds. So there is no need to feel sorry for it.","TWN":"不過，我們也不必感到遺憾，因為我們透過牧羊犬又重新讓新的種子開始發芽。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"아니, 오히려 이전보다 개선되었다고 봐야죠. 나무와 달리 셰퍼드에겐 사고능력이 있으니까요.","JPN":"いや、むしろ以前より改善されたと思うべきでしょう。木と違って、シェパードには思考能力がありますから。","ENG":"Rather, I see it as an improvement. Unlike the tree, Shepherd has cognitive abilities.","TWN":"不，它實際上比之前更加優秀。與樹木不同，牧羊犬擁有思考的能力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"어머? 셰퍼드가 저희에게 손을 흔드네요.","JPN":"あら？　シェパードが私たちに手を振ってますよ。","ENG":"Oh? Shepherd is waving her hand at us.","TWN":"喔？牧羊犬正在向我們招手。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"아무래도 아이일 때의 인격이 남아있나 봐요.","JPN":"どうやら子どものころの人格が残ってるようですね。","ENG":"I guess some of her personality as a child remain intact.","TWN":"看來她還殘留著一些身為孩童的性格。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"<color=#ffd34c>남아있다</color>라…","JPN":"<color=#ffd34c>残ってる</color>、か……","ENG":"<color=#ffd34c>Remain intact</color>...","TWN":"<color=#ffd34c>殘留</color>嗎……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"잘 모르겠네요. 이게 정말 <color=#ffd34c>우리</color>가 진정으로 원하던 건지.","JPN":"よくわかりませんね。これが本当に<color=#ffd34c>僕たち</color>が望んでいたことなのか。","ENG":"I'm a little skeptical. Is this truly what <color=#ffd34c>we</color> wanted?","TWN":"我不知道。這真的是<color=#ffd34c>我們</color>想要的嗎？"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"물론 바라던 결과죠. <color=#ff3636>저희</color> 프로젝트는 한 아이의 영혼뿐만 아니라, 수많은 인명을 구해내는 일이니까요.","JPN":"当然望んだ結果でしょう。<color=#ff3636>私たち</color>のプロジェクトは一人の子どもの魂だけでなく、多くの人の命を救うことですから。","ENG":"Of course. Through this result, <color=#ff3636>our</color> project has not just saved a child's soul, but the rest of humanity as well.","TWN":"當然。<color=#ff3636>我們</color>的項目不僅要拯救一個孩子的靈魂，還要拯救無數的生命。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"학계에서 처음으로 스프리건 인자의 보존 사례를 만드신 거예요.","JPN":"学会で初めてスプリガン因子の保存事例を残したんです。","ENG":"You are the first in the field to preserve the Spriggan Factor.","TWN":"你創造了學術界第一個成功保存守護者因子的案例。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"좀 더 자부심을 가지셔도 좋습니다, 프리하트 박사님.","JPN":"もっと自信を持ってください、プラハト博士。","ENG":"You can be proud of that achievement, Dr. Freeheart.","TWN":"你可以更驕傲一點，普立哈特博士。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"그 아이의 이름은 셰퍼드.","JPN":"その子の名前はシェパード。","ENG":"The child's name is Shepherd.","TWN":"那個孩子叫作牧羊犬。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체로부터 세계를 구하기 위해 스프리건 인자 합성으로 만들어진 인류의 수호자.","JPN":"侵食体から世界を救うために、スプリガン因子合成で作られた人類の守護者。","ENG":"Humanity's protector against C.O.s created through the Spriggan Factor synthesis.","TWN":"透過移植守護者因子而創造出來的人類守護者，目的是從侵蝕體中拯救世界。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"이미 잃어버린 것들을 돌려받진 못했지만, 그걸로 충분하다고… 내 멋대로 위안을 품었어.","JPN":"すでに失われたものは戻らなかったが、それでも十分だと……自分を励ました。","ENG":"Even though I couldn't get back what was already lost, I thought it was enough... And I took comfort in that.","TWN":"雖然失去的東西已無法挽回，但這已經足夠了……我這樣安慰著自己。"},"stage":{"bg":"LAB","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 얼마 지나지 않아, 그 선택이 잘못된 방향으로 흘러가고 있단 걸 알게 됐지.","JPN":"そしてそれから間もなくして、その選択が違う方向に向かっている事実を知るようになった。","ENG":"But not long after, I realized that my choice was heading in the wrong direction.","TWN":"很快，我就意識到我的選擇是錯誤的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"당황하지 마라, 셰퍼드.","JPN":"慌てるな、シェパード。","ENG":"Don't be alarmed, Shepherd.","TWN":"別驚慌，牧羊犬。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L48_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"지능이 없는 침식체를 통제하는 가장 손쉬운 방법은 그 안에 공포를 각인시키는 거다.","JPN":"知能のない侵食体をコントロールするもっとも簡単な方法は、その中に恐怖を刻むことだ。","ENG":"The easiest way to control C.O.s without intelligence is to imprint fear within them.","TWN":"要控制一個沒有智慧的侵蝕體，最簡單的方法就是將恐懼烙印在它身上。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"저것들이 널 두려워하게 만들어라. 널 따를 수밖에 없도록 말이지.","JPN":"あいつらがお前のことを恐れるようにしろ。お前に従うしかないようにな。","ENG":"Make them afraid of you. Give them no choice but to follow you.","TWN":"讓那些傢伙恐懼你，不得不跟隨你。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응, 알겠어요.","JPN":"うん、わかった。","ENG":"Okay.","TWN":"好的，牧羊犬知道了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"침식체가 저렇게 꼬리를 말고 도망치다니.","JPN":"侵食体が尻尾をまいて逃げるとは。","ENG":"A C.O. just fled like a dog with its tail tucked between its legs.","TWN":"哈哈！看到了嗎，侵蝕體像狗一樣夾著尾巴落荒而逃？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"박사님은 저런 광경을 보신 적 있습니까?","JPN":"博士あんな光景を見たことがありますか？","ENG":"Doctor, have you ever seen anything like this before?","TWN":"博士！你見過這樣的場景嗎？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"아뇨, 이론이 아닌 실제로는 저도 처음 봅니다.","JPN":"いえ、実際に目にしたのは僕も初めてです。","ENG":"No, this is also my first time seeing it.","TWN":"沒有，我也是第一次見到這樣的場景。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"정말 침식체가 감정을 느끼는 걸까요?","JPN":"本当に侵食体が感情を持っているのでしょうか。","ENG":"Does this mean that C.O.s actually have emotions?","TWN":"原來侵蝕體真的也有感情？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"글쎄요. 침식체는 신경전달물질을 분비하지 않습니다.","JPN":"どうでしょうか。侵食体は神経伝達物質を分泌しませんから。","ENG":"I don't know. But C.O.s don't secrete neurotransmitters.","TWN":"不好說。侵蝕體不會分泌神經遞質。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"셰퍼드가 보고 만지는 감정은 현대과학만으론 설명할 수 없는… 좀 더 근원적인 무언가에 있어요.","JPN":"シェパードが見て触れている感情は、現代科学だけでは説明できない……もっと根源的な何かにあります。","ENG":"The emotion Shepherd manipulates can't be explained by modern science alone... It's something more fundamental.","TWN":"牧羊犬所看到和觸摸到的情感，無法僅憑現代科學來解釋……那是更根源性的東西。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIOR_FLOOR_RESEARCH_NULL","text":{"KOREA":"가령, 영혼 같은 것 말입니까?","JPN":"例えば、魂のようなものですか？","ENG":"You mean, like souls?","TWN":"比如，靈魂？"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하하… 글쎄요. 기도를 하던 시절엔 그런 게 있을 거라 막연히 믿었다면…","JPN":"はは……さあ。祈りを捧げていた頃に、そんなものがあると漠然と信じていたとすれば……","ENG":"Haha... Perhaps. I used to vaguely believe in such stuff when I was a believer, but...","TWN":"呃，呵呵……這個嘛。如果我還有信仰，我大概會相信這種事情。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"지금은 그 실체를 보고 있는 느낌이네요.","JPN":"今まさにその実体を見ている感じですね。","ENG":"This is the first time seeing in with my eyes.","TWN":"我感覺自己發現了真相。"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIOR_FLOOR_RESEARCH_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"고생했구나, 셰퍼드.","JPN":"お疲れ、シェパード。","ENG":"You did well, Shepherd.","TWN":"辛苦了，牧羊犬。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"응, 검은 괴물. 어른 말대로 했더니 도망쳤어요.","JPN":"うん、黒い化け物。大人の言うとおりにしたら、逃げた。","ENG":"Uh-huh. The black monster. It ran away when Shepherd did as the adults said.","TWN":"嗯，黑色怪物。牧羊犬照著大人說的做了，它就逃跑了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"그래, 잘 했어.","JPN":"ああ、よくやったよ。","ENG":"Yes, good job.","TWN":"嗯，你做得很好。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하지만 공포는 나쁜 감정이니까, 사람에겐 함부로 주면 안 돼. 알겠지?","JPN":"でも恐怖は悪い感情だから、人には与えちゃダメだぞ。わかったか？","ENG":"But fear is a bad emotion. So you shouldn't imprint it on people, okay?","TWN":"但恐懼是一種不好的情緒，所以，不要輕易地把它帶給其他人。知道了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그렇구나. 나쁜 거 줬으니까, 검은 괴물이랑 친구 못하겠다.","JPN":"そうか。悪いもの与えたから、黒い化け物とは友だちになれないね。","ENG":"I see. Then because Shepherd gave something bad to the black monster, Shepherd and it can't become friends.","TWN":"這樣嗎？因為牧羊犬給了不好的東西，才不能和黑色的怪物做朋友。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"열심히 한 상으로, 특별히 원하는 거라도 있니?","JPN":"特別に頑張ったご褒美で、何かしたいことはあるかい？","ENG":"For your hard work, I'll give you a reward. Is there anything that you want?","TWN":"為了獎勵你的努力，你有什麼特別想要的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"음…","JPN":"うーん……","ENG":"Um...","TWN":"唔……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"차가운 곳에 가서 얼음 먹고 놀래요.","JPN":"冷たいところに行って、氷食べて遊ぶ。","ENG":"Shepherd wants to go somewhere cold to eat ice and play.","TWN":"牧羊犬想要去冷一點的地方，吃冰塊。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"괜찮죠, 이바나? 의료실 냉동고 개방 좀 부탁해요.","JPN":"いいですよね、イヴァナ？　医療室の冷凍庫の開放をお願いします。","ENG":"It's okay, right, Ivana? Could you open the medical bay's freezer?","TWN":"可以吧，伊維娜？拜託你打開醫務室的冰櫃。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"하아… 알겠어요. D동은 전파가 잘 안 통해서 보수가 필요하다니까, 너무 오래 있진 마시고요.","JPN":"はあ……わかりました。D棟は電波が悪くて補修が必要らしいですから、あまり長居はしないでくださいね。","ENG":"Ugh... All right. But D Wing needs maintenance as radio waves aren't working properly there. So don't stay in there for too long.","TWN":"哀……知道了。聽說D棟需要維修，那裡的電波訊號不太好，不要待得太久。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드, 냉장고 오래 있어도 괜찮아. 감기 안 걸려요.","JPN":"シェパード、冷蔵庫に長くいても平気。風邪ひかない。","ENG":"Shepherd is fine staying in the refrigerator for a long time. Shepherd can't catch colds.","TWN":"牧羊犬可以在冰箱裡待很久。不會感冒的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L35_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"넌 괜찮아도 박사님께서 감기에 걸리셔서 안돼.","JPN":"あなたは大丈夫でも、博士は風邪ひいちゃうからダメなの。","ENG":"You might be okay, but the doctor will catch a cold, so no.","TWN":"你或許沒事，但博士會感冒的，所以不行。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하하… 금방 다녀올게요.","JPN":"はは……すぐ行ってきます。","ENG":"Haha... We'll be back before you know it.","TWN":"哈哈……我們很快就回來。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"이거- 얼음 엄청 커.","JPN":"これ……氷、デカい。","ENG":"Look. The ice is so big.","TWN":"噢噢，這塊冰好大——"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"마음에 들어해서 다행이네.","JPN":"気に入ってもらってよかった。","ENG":"I'm glad you like it.","TWN":"喜歡嗎？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"셰퍼드는 얼음을 좋아하니까, 특별히 큰 걸로 준비해 봤는데.","JPN":"シェパード、氷が好きだから、特別に大きなものを用意してみたんだ。","ENG":"Since you like ice so much, I prepared this big one especially for you.","TWN":"牧羊犬喜歡冰塊，我就為你準備了一份特別大的。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"명령권자는 착해요.","JPN":"命令権者は優しい人。","ENG":"You are kind, commander.","TWN":"指揮官，對牧羊犬很好。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"우리 둘만 있을 땐 그런 딱딱한 표현으로 부르지 않아도 돼.","JPN":"二人だけの時は、そんな堅苦しい呼び方じゃなくてもいいぞ。","ENG":"You know you don't have to be strict with titles when it's just us two.","TWN":"只有我們兩個人的時候，可以不用那麼一板一眼地的稱呼我。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"딱딱? 명령권자, 그럼 뭐라고 불러요?","JPN":"堅苦しい？　命令権者、じゃあなんて呼べばいいの？","ENG":"Strict? Commander, then what should Shepherd call you?","TWN":"一板一眼？指揮官，那我要叫你什麼？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"음… 그러게…","JPN":"うーん……そうだな……","ENG":"Um... well...","TWN":"唔……我想想……"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"<color=#ffd34c>널 아끼는 사람</color>. 어떠니?","JPN":"<color=#ffd34c>君を大切に思っている人</color>。どうだ？","ENG":"How about, <color=#ffd34c>the person dear to you</color>?","TWN":"不如叫<color=#ffd34c>在乎牧羊犬的人</color>，你覺得怎麼樣？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"날… 아끼는 사람.","JPN":"シェパードを……大切に思っている人。","ENG":"The person... dear to Shepherd.","TWN":"在乎……牧羊犬的人。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"길고 비효율적인 호칭.","JPN":"長くて非効率的な呼び方。","ENG":"A long and inefficient title.","TWN":"又長又麻煩的稱呼。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하하… 역시 그렇지?","JPN":"はは……やっぱりそうかな？","ENG":"Haha... I guess you're right.","TWN":"哈哈……也是啊？"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그래도 좋아요.","JPN":"でも、いいよ。","ENG":"But Shepherd likes it.","TWN":"不過牧羊犬喜歡。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그렇게 말하니까, 두근두근해. 기분 좋았어요.","JPN":"言ってみたら、何かドキドキする。嬉しい。","ENG":"Calling you that makes Shepherd's heart go pitter-patter. It feels good.","TWN":"這麼說的時候，牧羊犬心在砰砰地跳。感覺很好。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"하하, 셰퍼드가 마음에 든다니 나도 기쁘네.","JPN":"はは、シェパードに気に入ってもらえて僕も嬉しいよ。","ENG":"Haha. If you like it, then I like it too.","TWN":"哈哈，你喜歡就好，牧羊犬。"},"stage":{"bg":"WAREHOUSE_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L6_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"셰퍼드…?!","JPN":"シェパード……！？","ENG":"Shepherd...?!","TWN":"牧羊犬……？！"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};